import{_ as r,o,c as a,a5 as t}from"./chunks/framework.DYHZIppx.js";const h=JSON.parse('{"title":"workers/diff-worker-client","description":"","frontmatter":{},"headers":[],"relativePath":"api/workers.diff-worker-client.md","filePath":"api/workers.diff-worker-client.md"}'),i={name:"api/workers.diff-worker-client.md"};function n(d,e,c,s,f,l){return o(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="workers-diff-worker-client" tabindex="-1">workers/diff-worker-client <a class="header-anchor" href="#workers-diff-worker-client" aria-label="Permalink to &quot;workers/diff-worker-client&quot;">​</a></h1><p>Diff Worker 클라이언트 — Promise 기반 비동기 인터페이스</p><p><code>diff.worker.js</code>와 메인 스레드 사이의 <code>postMessage</code> / <code>onmessage</code> 통신을 Promise API로 감싸 <code>DomainState.save()</code>에서 <code>await</code>로 사용할 수 있도록 한다.</p><h2 id="설계-원칙" tabindex="-1">설계 원칙 <a class="header-anchor" href="#설계-원칙" aria-label="Permalink to &quot;설계 원칙&quot;">​</a></h2><h3 id="lazy-singleton-패턴" tabindex="-1">Lazy Singleton 패턴 <a class="header-anchor" href="#lazy-singleton-패턴" aria-label="Permalink to &quot;Lazy Singleton 패턴&quot;">​</a></h3><p>Worker 인스턴스는 첫 번째 <code>requestDiff()</code> 호출 시 단 1회 생성된다. 이후 모든 <code>requestDiff()</code> 호출이 동일한 Worker 인스턴스를 재사용한다. 사용하지 않으면 Worker가 생성되지 않아 메모리를 낭비하지 않는다.</p><h3 id="동시성-안전-concurrency-safety" tabindex="-1">동시성 안전 (Concurrency Safety) <a class="header-anchor" href="#동시성-안전-concurrency-safety" aria-label="Permalink to &quot;동시성 안전 (Concurrency Safety)&quot;">​</a></h3><p>여러 <code>DomainState</code> 인스턴스가 동시에 <code>save()</code>를 호출할 수 있다. 각 요청에 고유한 <code>_requestId</code>를 부여하고, 응답 수신 시 ID로 매칭한다. <code>_pending Map</code>에서 해당 ID의 Promise를 꺼내 resolve/reject한다.</p><h3 id="node-js-vitest-폴백" tabindex="-1">Node.js / Vitest 폴백 <a class="header-anchor" href="#node-js-vitest-폴백" aria-label="Permalink to &quot;Node.js / Vitest 폴백&quot;">​</a></h3><p><code>typeof Worker === &#39;undefined&#39;</code>인 Node.js 환경(Vitest, SSR)에서는 Worker 없이 <code>deepDiff()</code>를 <strong>동기적으로</strong> 직접 호출한다. 테스트 격리가 완전하고, 비동기 메시지 대기 없이 동일한 로직을 검증할 수 있다.</p><h3 id="worker-에러-복구" tabindex="-1">Worker 에러 복구 <a class="header-anchor" href="#worker-에러-복구" aria-label="Permalink to &quot;Worker 에러 복구&quot;">​</a></h3><p>Worker가 치명적 에러로 종료되면 <code>_pending</code> 전체를 reject하고 <code>_worker = null</code>로 초기화한다. 다음 <code>requestDiff()</code> 호출 시 Worker가 재생성된다.</p><h2 id="see" tabindex="-1">See <a class="header-anchor" href="#see" aria-label="Permalink to &quot;See&quot;">​</a></h2><ul><li>module:workers/diff.worker diff.worker</li><li>module:common/lcs-diff deepDiff</li></ul><h2 id="interfaces" tabindex="-1">Interfaces <a class="header-anchor" href="#interfaces" aria-label="Permalink to &quot;Interfaces&quot;">​</a></h2><ul><li><a href="./workers.diff-worker-client.Interface.ChangeLogEntry">ChangeLogEntry</a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><ul><li><a href="./workers.diff-worker-client.Function.requestDiff">requestDiff</a></li><li><a href="./workers.diff-worker-client.Function.terminateDiffWorker">terminateDiffWorker</a></li></ul>',18)])])}const u=r(i,[["render",n]]);export{h as __pageData,u as default};
